"""Django settings for the Ollama-backed chat SPA."""

from __future__ import annotations

import os
from pathlib import Path

BASE_DIR = Path(__file__).resolve().parent.parent


def _required_env(name: str) -> str:
    """Return env var ``name`` or raise — no insecure fallbacks in source."""
    value = os.environ.get(name)
    if not value:
        raise RuntimeError(
            f"Environment variable {name!r} must be set "
            "(no hardcoded fallback is permitted in source)."
        )
    return value


# SECURITY: SECRET_KEY is required from the environment. There is intentionally
# no in-source fallback so that a missing key fails fast rather than silently
# using an insecure literal.
SECRET_KEY: str = _required_env("DJANGO_SECRET_KEY")

DEBUG: bool = os.environ.get("DJANGO_DEBUG", "false").lower() in {"1", "true", "yes"}

