"""Thin wrapper around langchain-ollama's ``ChatOllama`` streaming API.

Kept deliberately small so consumers depend on a stable async-iterator
interface that's trivial to fake in tests. All Ollama config comes from
Django settings, which themselves come from ``OLLAMA_HOST`` and
``OLLAMA_MODEL`` environment variables.
"""

from __future__ import annotations

from collections.abc import AsyncIterator, Iterable
from dataclasses import dataclass
from typing import Protocol

from django.conf import settings
from langchain_core.messages import AIMessage, BaseMessage, HumanMessage, SystemMessage
from langchain_ollama import ChatOllama

DEFAULT_SYSTEM_PROMPT = "You are a concise, helpful assistant. Answer the user's question directly."


@dataclass(frozen=True, slots=True)
class ChatTurn:
    """One message in the rolling chat history."""

    role: str  # "user" | "assistant" | "system"
    content: str


class TokenStreamer(Protocol):
    """Anything that can stream tokens for a given history."""

    def stream(
        self, history: Iterable[ChatTurn]
    ) -> AsyncIterator[str]:  # pragma: no cover - protocol
        ...


def _to_langchain_messages(history: Iterable[ChatTurn]) -> list[BaseMessage]:
    out: list[BaseMessage] = []
    for turn in history:
        if turn.role == "system":
            out.append(SystemMessage(content=turn.content))
        elif turn.role == "assistant":
            out.append(AIMessage(content=turn.content))
        else:
            out.append(HumanMessage(content=turn.content))
    return out


class OllamaChatStreamer:
    """Real ``ChatOllama`` streamer; produced by :func:`build_default_streamer`."""

    def __init__(self, *, model: str, base_url: str) -> None:
        # ``astream`` is what actually drives token streaming; ``streaming=True``
        # is a hint kept for compatibility with older langchain-ollama releases.
        self._client = ChatOllama(  # type: ignore[call-arg]
            model=model,
            base_url=base_url,
            streaming=True,
        )

    async def stream(self, history: Iterable[ChatTurn]) -> AsyncIterator[str]:
        messages = _to_langchain_messages(history)
        if not any(isinstance(m, SystemMessage) for m in messages):
            messages.insert(0, SystemMessage(content=DEFAULT_SYSTEM_PROMPT))
        async for chunk in self._client.astream(messages):
            text = getattr(chunk, "content", "") or ""
            if text:
                yield text


def build_default_streamer() -> TokenStreamer:
    """Construct the production streamer from Django settings."""
    return OllamaChatStreamer(
        model=settings.OLLAMA_MODEL,
        base_url=settings.OLLAMA_HOST,
    )

"""HTTP views — just the SPA shell. All chat traffic flows over the WS."""

from __future__ import annotations

from django.conf import settings
from django.http import HttpRequest, HttpResponse
from django.shortcuts import render


def index(request: HttpRequest) -> HttpResponse:
    """Render the single-page chat shell."""
    return render(
        request,
        "chat/index.html",
        {
            "model_name": settings.OLLAMA_MODEL,
        },
    )


def healthz(request: HttpRequest) -> HttpResponse:
    """Tiny liveness probe — handy for compose healthchecks."""
    return HttpResponse("ok", content_type="text/plain")

